func hashPassword(_ password: String) -> String {
    var digest = [UInt8](repeating: 0, count: Int(CC_SHA256_DIGEST_LENGTH))
    
    let passwordData = password.data(using: .utf8)!
    withUnsafeBytes(of: passwordData) {
        CC_SHA256($0, CC_LONG(passwordData.count), &digest)
    }
    
    var hashString = ""
    for byte in digest {
        hashString += String(format: "%02hhx", byte)
    }
    
    return hashString
}

func verifyPassword(_ password: String, _ storedHash: String) -> Bool {
